sp_widget.client_script:
api.controller = function($scope) {
  var c = this;

  // server gives us stats and the full doctors map up front
  c.stats        = c.data.stats        || {};
  var _doctorsMap = c.data.doctorsByDept || {}; // { dept: [{name, sys_id}] }
  // log the exact dept keys from the DB so you can compare vs HTML option values
  console.log('[SmartCare] doctorsByDept keys:', c.data.doctorDepts || Object.keys(_doctorsMap));

  // modal state
  c.modalOpen   = false;
  c.formState   = 'form'; // 'form' | 'success' | 'error'
  c.submitting  = false;
  c.errorDetail = '';
  c.successName = '';
  c.successRef  = '';
  c.minDate     = '';
  c.fieldErrors = {};

  // form model
  c.form = {
    name: '', phone: '', email: '',
    gender: '', age: '',
    dept: '', doctor: '', date: '', time: '', notes: ''
  };

  // doctor dropdown (populated from server-provided map, no REST calls needed)
  c.doctors    = [];
  c.docLoading = false;

  // ── modal helpers ──────────────────────────────────
  c.openModal = function() {
    c.modalOpen = true;
    c.formState = 'form';
    c.minDate   = new Date().toISOString().split('T')[0];
  };

  c.closeModal = function() {
    c.modalOpen = false;
    setTimeout(function() {
      $scope.$apply(function() {
        c.formState   = 'form';
        c.submitting  = false;
        c.form        = { name:'', phone:'', email:'', dept:'', doctor:'', date:'', time:'', notes:'' };
        c.doctors     = [];
        c.fieldErrors = {};
      });
    }, 350);
  };

  c.overlayClick = function($event) {
    if (angular.element($event.target).hasClass('sc-modal-overlay')) {
      c.closeModal();
    }
  };

  c.retryForm = function() {
    c.formState  = 'form';
    c.submitting = false;
  };

  // ── doctor filter (purely from server-provided data, no $http) ─────
  c.filterDoctorsByDept = function() {
    var dept      = c.form.dept;
    c.form.doctor = '';
    c.doctors     = dept ? (_doctorsMap[dept] || []) : [];
  };

  // ── submit appointment via server.update() (no REST, no 401) ───────
  c.submitAppointment = function() {
    var f = c.form;
    c.fieldErrors = {};
    var valid = true;
    ['name','phone','gender','age','dept','doctor','date','time'].forEach(function(k) {
      if (!f[k]) { c.fieldErrors[k] = true; valid = false; }
    });
    // debug — open DevTools console to see exactly what the form contains on submit
    console.log('[SmartCare] form on submit:', JSON.stringify(f));
    console.log('[SmartCare] fieldErrors:', JSON.stringify(c.fieldErrors));
    if (!valid) return;

    c.submitting = true;

    // c.server.get() sends custom params as `input` on the server side
    c.server.get({
      action: 'submitAppointment',
      form: {
        name:   f.name,
        phone:  f.phone,
        email:  f.email,
        gender: f.gender,
        age:    f.age,
        dept:   f.dept,
        doctor: f.doctor,
        date:   f.date,
        time:   f.time,
        notes:  f.notes
      }
    }).then(function(response) {
      // c.server.get() passes the fresh data as a .then() argument — c.data is NOT auto-updated
      var serverData = (response && response.data) ? response.data : (response || {});
      var result = serverData.submitResult || {};

      if (result.ok) {
        c.successName = f.name;
        c.successRef  = 'SC-' + (result.sys_id || '').substring(0, 8).toUpperCase();
        c.formState   = 'success';
      } else {
        c.errorDetail = result.error || 'Unexpected error from server';
        c.formState   = 'error';
      }
    }).catch(function(err) {
      c.errorDetail = err ? String(err) : 'Server call failed';
      c.formState   = 'error';
    }).finally(function() {
      c.submitting = false;
    });
  };

  // ── scroll animations ──────────────────────────────
  function initScrollAnimations() {
    var els = document.querySelectorAll('.sc-dcard,.sc-doc-card,.sc-tcard,.sc-qcard,.sc-why-item,.sc-jstep');
    var obs = new IntersectionObserver(function(entries) {
      entries.forEach(function(entry) {
        if (entry.isIntersecting) {
          var delay = parseInt(entry.target.dataset.i || 0) * 85;
          setTimeout(function() {
            entry.target.style.opacity   = '1';
            entry.target.style.transform = 'translateY(0)';
          }, delay);
          obs.unobserve(entry.target);
        }
      });
    }, { threshold: 0.08 });

    els.forEach(function(el, i) {
      el.style.opacity    = '0';
      el.style.transform  = 'translateY(20px)';
      el.style.transition = 'opacity .5s ease, transform .5s ease';
      el.dataset.i        = i % 6;
      obs.observe(el);
    });

    $scope.$on('$destroy', function() { obs.disconnect(); });
  }

  // ── counter animations ─────────────────────────────
  function animateCounter(el) {
    var raw    = el.textContent.trim();
    var num    = parseInt(raw.replace(/[^0-9]/g, ''), 10);
    if (isNaN(num) || num === 0) return;
    var suffix = raw.replace(/[0-9,]/g, '');
    var start  = null, dur = 1500;
    function tick(ts) {
      if (!start) start = ts;
      var p = Math.min((ts - start) / dur, 1), ease = 1 - Math.pow(1 - p, 3);
      el.textContent = Math.floor(ease * num).toLocaleString() + suffix;
      if (p < 1) requestAnimationFrame(tick);
    }
    requestAnimationFrame(tick);
  }

  function initCounters() {
    var cObs = new IntersectionObserver(function(entries) {
      entries.forEach(function(e) {
        if (e.isIntersecting) { animateCounter(e.target); cObs.unobserve(e.target); }
      });
    }, { threshold: 0.5 });
    setTimeout(function() {
      document.querySelectorAll('.sc-tn').forEach(function(el) { cObs.observe(el); });
    }, 1500);
    $scope.$on('$destroy', function() { cObs.disconnect(); });
  }

  // boot animations after render
  setTimeout(function() {
    initScrollAnimations();
    initCounters();
  }, 300);

  // keyboard: Escape closes modal
  function onKeyDown(e) {
    if (e.key === 'Escape') $scope.$apply(function() { c.closeModal(); });
  }
  document.addEventListener('keydown', onKeyDown);
  $scope.$on('$destroy', function() { document.removeEventListener('keydown', onKeyDown); });
};

sp_widget.css:
@import url('https://fonts.googleapis.com/css2?family=Playfair+Display:ital,wght@0,600;0,700;0,800;1,700&family=Inter:wght@300;400;500;600;700&display=swap');

.sc-widget *, .sc-widget *::before, .sc-widget *::after { box-sizing: border-box; margin: 0; padding: 0; }
/* Force 16px base — SNow portal Bootstrap uses 14px which shrinks all rem values */
.sc-widget { font-family: 'Inter', sans-serif; font-size: 16px !important; color: #1a2b45; background: #fff; line-height: 1.65; overflow-x: hidden; }
/* Reset Bootstrap heading overrides inside the widget */
.sc-widget h1, .sc-widget h2, .sc-widget h3 { font-family: 'Playfair Display', serif; font-weight: 800; line-height: 1.15; margin: 0; border: none; padding: 0; }
.sc-widget a { text-decoration: none; color: inherit; }
.sc-widget img { display: block; max-width: 100%; }
.sc-widget ul, .sc-widget ol { padding: 0; margin: 0; }
.sc-widget button, .sc-widget input, .sc-widget select, .sc-widget textarea { font-family: 'Inter', sans-serif; }

/* CSS VARIABLES (as literals for widget compat) */
/* --navy:#0b2545 --blue:#0d5eaf --blue-m:#1971d2 --blue-lt:#e8f2fc --teal:#00a99d --teal-lt:#e4f7f6 */

/* ─── TOP STRIP ─── */
.sc-strip { background: #0b2545; padding: 7px 2rem; display: flex; justify-content: space-between; align-items: center; font-size: 12.4px; color: rgba(255,255,255,.68); }
.sc-strip-left { display: flex; align-items: center; gap: 1.4rem; }
.sc-strip-item { display: flex; align-items: center; gap: 5px; }
.sc-strip-item svg { width: 13px; height: 13px; fill: #00a99d; }
.sc-emerg { display: flex; align-items: center; gap: 6px; background: #dc2626; color: #fff; padding: 3px 12px; border-radius: 100px; font-weight: 700; font-size: 11.5px; letter-spacing: .05em; }
.sc-emerg::before { content: ''; width: 7px; height: 7px; border-radius: 50%; background: #fff; animation: sc-blink 1.2s infinite; }
@keyframes sc-blink { 0%,100%{opacity:1} 50%{opacity:.3} }

/* ─── NAVBAR ─── */
.sc-nav { position: sticky; top: 0; z-index: 999; background: #fff; border-bottom: 1px solid #dce8f5; height: 74px; padding: 0 2rem; display: flex; align-items: center; justify-content: space-between; box-shadow: 0 2px 10px rgba(11,37,69,.07); }
.sc-logo img { height: 48px; width: auto; }
.sc-nav-menu { display: flex; gap: .1rem; list-style: none; }
.sc-nav-menu a { color: #1a2b45; font-size: 14px; font-weight: 500; padding: 7px 14px; border-radius: 7px; transition: all .2s; }
.sc-nav-menu a:hover { background: #e8f2fc; color: #0d5eaf; }
.sc-nav-btns { display: flex; gap: .7rem; align-items: center; }
.sc-nb-outline { border: 1.5px solid #0d5eaf; color: #0d5eaf; padding: 7px 17px; border-radius: 8px; font-size: 13.4px; font-weight: 600; transition: all .2s; }
.sc-nb-outline:hover { background: #0d5eaf; color: #fff; }
.sc-nb-fill { background: #0d5eaf; color: #fff; padding: 8px 20px; border-radius: 8px; font-size: 13.4px; font-weight: 700; transition: all .2s; box-shadow: 0 3px 14px rgba(13,94,175,.3); cursor: pointer; border: none; }
.sc-nb-fill:hover { background: #0b2545; transform: translateY(-1px); }

/* ─── HERO ─── */
.sc-hero { position: relative; min-height: 92vh; display: flex; align-items: center; overflow: hidden; }
.sc-hero-bg { position: absolute; inset: 0; background: url('https://images.unsplash.com/photo-1586773860418-d37222d8fce3?w=1800&q=80') center 30%/cover; }
.sc-hero-ov { position: absolute; inset: 0; background: linear-gradient(105deg, rgba(11,37,69,.9) 0%, rgba(11,37,69,.65) 52%, rgba(13,94,175,.28) 100%); }
.sc-hero-inner { position: relative; z-index: 2; max-width: 1200px; margin: 0 auto; padding: 0 2rem; width: 100%; }
.sc-hero-eyebrow { display: inline-flex; align-items: center; gap: 8px; color: #7ed8d3; font-size: 12.5px; font-weight: 600; letter-spacing: .1em; text-transform: uppercase; margin-bottom: 20px; animation: sc-up .7s ease both; }
.sc-hero-eyebrow span { width: 28px; height: 1.5px; background: #00a99d; }
.sc-hero h1 { font-size: clamp(41.6px, 5.5vw, 68.8px); font-weight: 800; color: #fff; line-height: 1.08; letter-spacing: -.025em; max-width: 640px; margin-bottom: 20px; animation: sc-up .7s .1s ease both; }
.sc-hero h1 em { font-style: italic; color: #7ed8d3; }
.sc-hero-sub { font-size: 17.3px; color: rgba(255,255,255,.76); max-width: 490px; line-height: 1.78; font-weight: 300; margin-bottom: 38px; animation: sc-up .7s .2s ease both; }
.sc-hero-actions { display: flex; flex-wrap: wrap; gap: 1rem; animation: sc-up .7s .3s ease both; }
@keyframes sc-up { from{opacity:0;transform:translateY(26px)} to{opacity:1;transform:translateY(0)} }

.sc-btn-teal { background: #00a99d; color: #fff; padding: 14px 32px; border-radius: 10px; font-weight: 700; font-size: 15.2px; display: inline-flex; align-items: center; gap: 8px; transition: all .25s; box-shadow: 0 6px 24px rgba(0,169,157,.45); cursor: pointer; border: none; }
.sc-btn-teal:hover { background: #009088; transform: translateY(-3px); }
.sc-btn-ghost { background: transparent; border: 2px solid rgba(255,255,255,.42); color: #fff; padding: 14px 32px; border-radius: 10px; font-weight: 600; font-size: 15.2px; display: inline-flex; align-items: center; gap: 8px; transition: all .25s; }
.sc-btn-ghost:hover { border-color: #fff; background: rgba(255,255,255,.12); transform: translateY(-3px); }
.sc-btn-teal svg, .sc-btn-ghost svg { width: 18px; height: 18px; fill: currentColor; }

/* floating card */
.sc-hero-float { position: absolute; right: 4rem; bottom: 3.5rem; z-index: 3; background: #fff; border-radius: 16px; padding: 1.6rem; width: 285px; box-shadow: 0 24px 64px rgba(11,37,69,.15); animation: sc-up .8s .55s ease both; }
.sc-hf-head { font-size: 11.2px; font-weight: 700; letter-spacing: .1em; text-transform: uppercase; color: #0d5eaf; margin-bottom: 13.6px; }
.sc-hf-row { display: flex; align-items: center; gap: 10px; padding: 8.8px 0; border-bottom: 1px solid #dce8f5; }
.sc-hf-row:last-of-type { border: none; }
.sc-hf-ico { width: 36px; height: 36px; border-radius: 8px; background: #e8f2fc; display: flex; align-items: center; justify-content: center; flex-shrink: 0; }
.sc-hf-ico svg { width: 18px; height: 18px; fill: #0d5eaf; }
.sc-hf-lbl { font-size: 11.2px; color: #566983; }
.sc-hf-val { font-size: 14px; font-weight: 700; color: #0b2545; }
.sc-hf-btn { margin-top: 1rem; width: 100%; padding: 10.9px; background: #0d5eaf; color: #fff; border: none; border-radius: 8px; font-weight: 700; font-size: 14px; cursor: pointer; transition: background .2s; }
.sc-hf-btn:hover { background: #0b2545; }

/* ─── TRUST BAR ─── */
.sc-trust { background: #0b2545; padding: 1.6rem 2rem; }
.sc-trust-inner { max-width: 1200px; margin: 0 auto; display: grid; grid-template-columns: repeat(4,1fr); gap: 1px; background: rgba(255,255,255,.08); border-radius: 12px; overflow: hidden; }
.sc-trust-cell { background: rgba(11,37,69,.85); padding: 1.35rem 1.5rem; display: flex; align-items: center; gap: 12px; }
.sc-ti { width: 44px; height: 44px; border-radius: 10px; background: rgba(0,169,157,.18); display: flex; align-items: center; justify-content: center; flex-shrink: 0; }
.sc-ti svg { width: 22px; height: 22px; fill: #00a99d; }
.sc-tn { font-family: 'Playfair Display', serif; font-size: 24px; font-weight: 700; color: #fff; line-height: 1; }
.sc-tl { font-size: 12.2px; color: rgba(255,255,255,.5); margin-top: 2px; }

/* ─── SHARED ─── */
.sc-section { padding: 5rem 2rem; }
.sc-cnt { max-width: 1200px; margin: 0 auto; }
.sc-pill { display: inline-block; padding: 4px 14px; border-radius: 100px; font-size: .7rem; font-weight: 700; letter-spacing: .09em; text-transform: uppercase; background: #e8f2fc; color: #0d5eaf; margin-bottom: .7rem; }
.sc-pill.t { background: #e4f7f6; color: #00a99d; }
.sc-sh { font-size: clamp(28px, 3.5vw, 40px); font-weight: 800; color: #0b2545; letter-spacing: -.025em; line-height: 1.15; margin-bottom: 12.8px; }
.sc-sp { font-size: 16px; color: #566983; line-height: 1.75; max-width: 500px; margin-bottom: 44px; }
.sc-center { text-align: center; }
.sc-center .sc-sp { margin-left: auto; margin-right: auto; }
.sc-row-head { display: flex; justify-content: space-between; align-items: flex-end; flex-wrap: wrap; gap: 1rem; margin-bottom: 2.5rem; }
.sc-see-all { color: #0d5eaf; font-weight: 700; font-size: .875rem; display: flex; align-items: center; gap: 5px; }
.sc-see-all svg { width: 14px; height: 14px; fill: #0d5eaf; }

/* ─── QUICK ACCESS ─── */
.sc-quick { background: #f7fafd; padding: 3.5rem 2rem; }
.sc-qgrid { display: grid; grid-template-columns: repeat(4,1fr); gap: 1.2rem; }
.sc-qcard { background: #fff; border-radius: 12px; border: 1px solid #dce8f5; padding: 1.75rem 1.4rem; display: flex; flex-direction: column; align-items: flex-start; gap: .85rem; box-shadow: 0 2px 10px rgba(11,37,69,.07); cursor: pointer; transition: all .28s; position: relative; overflow: hidden; }
.sc-qcard:hover { transform: translateY(-6px); box-shadow: 0 24px 64px rgba(11,37,69,.15); border-color: transparent; }
.sc-qcard:hover .sc-qi { background: #0d5eaf; }
.sc-qcard:hover .sc-qi svg { fill: #fff; }
.sc-qbar { position: absolute; top: 0; left: 0; right: 0; height: 4px; }
.sc-qi { width: 48px; height: 48px; border-radius: 10px; background: #e8f2fc; display: flex; align-items: center; justify-content: center; transition: all .28s; }
.sc-qi svg { width: 22px; height: 22px; fill: #0d5eaf; transition: fill .28s; }
.sc-qcard h4 { font-family: 'Inter', sans-serif; font-size: 15.2px; font-weight: 700; color: #0b2545; }
.sc-qcard p { font-size: 12.8px; color: #566983; }
.sc-qarr { margin-top: auto; align-self: flex-end; width: 28px; height: 28px; border-radius: 50%; background: #f7fafd; display: flex; align-items: center; justify-content: center; }
.sc-qarr svg { width: 14px; height: 14px; fill: #566983; }

/* ─── DEPARTMENTS ─── */
.sc-depts { background: #fff; }
.sc-dgrid { display: grid; grid-template-columns: repeat(3,1fr); gap: 1.5rem; }
.sc-dcard { border-radius: 12px; overflow: hidden; border: 1px solid #dce8f5; box-shadow: 0 2px 10px rgba(11,37,69,.07); transition: all .3s; cursor: pointer; display: flex; flex-direction: column; }
.sc-dcard:hover { transform: translateY(-6px); box-shadow: 0 24px 64px rgba(11,37,69,.15); border-color: transparent; }
.sc-dcard-img { position: relative; overflow: hidden; }
.sc-dcard-img img { width: 100%; height: 190px; object-fit: cover; transition: transform .5s; }
.sc-dcard:hover .sc-dcard-img img { transform: scale(1.06); }
.sc-dcard-img::after { content: ''; position: absolute; inset: 0; background: linear-gradient(to top, rgba(11,37,69,.5) 0%, transparent 55%); }
.sc-dbody { padding: 1.4rem 1.5rem; flex: 1; display: flex; flex-direction: column; }
.sc-dtag { display: inline-block; font-size: 10.7px; font-weight: 700; letter-spacing: .08em; text-transform: uppercase; color: #0d5eaf; background: #e8f2fc; padding: 3px 10px; border-radius: 100px; margin-bottom: 8.8px; }
.sc-dbody h3 { font-family: 'Inter', sans-serif; font-size: 15.7px; font-weight: 700; color: #0b2545; margin-bottom: 5.6px; }
.sc-dbody p { font-size: 13.1px; color: #566983; line-height: 1.65; flex: 1; }
.sc-dlink { margin-top: 1rem; font-size: 12.8px; font-weight: 700; color: #0d5eaf; display: flex; align-items: center; gap: 5px; transition: gap .2s; }
.sc-dcard:hover .sc-dlink { gap: 9px; }
.sc-dlink svg { width: 14px; height: 14px; fill: #0d5eaf; }

/* ─── DOCTORS ─── */
.sc-docs { background: #f7fafd; }
.sc-doc-grid { display: grid; grid-template-columns: repeat(4,1fr); gap: 1.2rem; }
.sc-doc-card { background: #fff; border-radius: 12px; border: 1px solid #dce8f5; overflow: hidden; box-shadow: 0 2px 10px rgba(11,37,69,.07); transition: all .3s; }
.sc-doc-card:hover { transform: translateY(-5px); box-shadow: 0 24px 64px rgba(11,37,69,.15); }
.sc-doc-photo { position: relative; }
.sc-doc-photo img { width: 100%; height: 220px; object-fit: cover; object-position: top; }
.sc-doc-avail { position: absolute; bottom: 10px; left: 10px; background: #fff; border-radius: 100px; padding: 4px 10px; font-size: 10.9px; font-weight: 700; display: flex; align-items: center; gap: 5px; color: #15803d; }
.sc-doc-avail::before { content: ''; width: 7px; height: 7px; border-radius: 50%; background: #22c55e; }
.sc-doc-body { padding: 19px 21px; }
.sc-doc-spec { font-size: 11.2px; font-weight: 700; letter-spacing: .06em; text-transform: uppercase; color: #00a99d; margin-bottom: 4.8px; }
.sc-doc-body h3 { font-family: 'Inter', sans-serif; font-size: 15.5px; font-weight: 700; color: #0b2545; margin-bottom: 2.4px; }
.sc-doc-qual { font-size: 12px; color: #566983; margin-bottom: 14.4px; }
.sc-doc-btn { width: 100%; padding: 8.8px; border-radius: 8px; border: 1.5px solid #0d5eaf; color: #0d5eaf; background: transparent; font-weight: 700; font-size: 12.8px; cursor: pointer; transition: all .2s; }
.sc-doc-btn:hover { background: #0d5eaf; color: #fff; }

/* ─── WHY US ─── */
.sc-why { background: #0b2545; position: relative; overflow: hidden; padding: 5rem 2rem; }
.sc-why::before { content: ''; position: absolute; width: 600px; height: 600px; border-radius: 50%; background: radial-gradient(circle, rgba(0,169,157,.1) 0%, transparent 70%); top: -200px; right: -100px; }
.sc-why-grid { display: grid; grid-template-columns: 1fr 1fr; gap: 4rem; align-items: center; max-width: 1200px; margin: 0 auto; }
.sc-why-left { position: relative; }
.sc-why-left img { width: 100%; height: 500px; object-fit: cover; border-radius: 16px; box-shadow: 0 24px 64px rgba(11,37,69,.15); }
.sc-why-badge { position: absolute; bottom: -20px; right: -20px; background: #00a99d; color: #fff; border-radius: 14px; padding: 1.4rem 1.6rem; text-align: center; box-shadow: 0 8px 36px rgba(11,37,69,.11); }
.sc-why-badge strong { font-family: 'Playfair Display', serif; font-size: 35.2px; font-weight: 800; display: block; line-height: 1; }
.sc-why-badge span { font-size: 12.2px; opacity: .88; }
.sc-why .sc-pill { background: rgba(0,169,157,.15); color: #7ed8d3; }
.sc-why .sc-sh { color: #fff; }
.sc-why .sc-sp { color: rgba(255,255,255,.6); margin-bottom: 2rem; }
.sc-why-list { display: flex; flex-direction: column; gap: 1rem; }
.sc-why-item { display: flex; gap: 1rem; align-items: flex-start; background: rgba(255,255,255,.05); border-radius: 10px; padding: 1.1rem 1.2rem; border: 1px solid rgba(255,255,255,.07); transition: background .25s; }
.sc-why-item:hover { background: rgba(255,255,255,.09); }
.sc-wii { width: 42px; height: 42px; border-radius: 9px; background: rgba(0,169,157,.2); display: flex; align-items: center; justify-content: center; flex-shrink: 0; }
.sc-wii svg { width: 20px; height: 20px; fill: #00a99d; }
.sc-wit { font-family: 'Inter', sans-serif; font-size: 14.7px; font-weight: 700; color: #fff; margin-bottom: 3px; }
.sc-wid { font-size: 12.8px; color: rgba(255,255,255,.52); line-height: 1.6; }

/* ─── JOURNEY ─── */
.sc-journey { background: #f7fafd; }
.sc-jsteps { display: grid; grid-template-columns: repeat(6,1fr); gap: 0; margin-top: 3rem; position: relative; }
.sc-jsteps::before { content: ''; position: absolute; top: 35px; left: calc(8.33% + 10px); right: calc(8.33% + 10px); height: 2px; background: #dce8f5; }
.sc-jstep { display: flex; flex-direction: column; align-items: center; text-align: center; }
.sc-jcircle { width: 70px; height: 70px; border-radius: 50%; background: #fff; border: 2px solid #dce8f5; display: flex; align-items: center; justify-content: center; margin-bottom: .9rem; position: relative; z-index: 1; transition: all .3s; box-shadow: 0 2px 10px rgba(11,37,69,.07); }
.sc-jcircle svg { width: 26px; height: 26px; fill: #566983; transition: fill .3s; }
.sc-jstep:hover .sc-jcircle { background: #0d5eaf; border-color: #0d5eaf; box-shadow: 0 0 0 8px rgba(13,94,175,.12); }
.sc-jstep:hover .sc-jcircle svg { fill: #fff; }
.sc-jnum { position: absolute; top: -5px; right: -5px; width: 22px; height: 22px; border-radius: 50%; background: #00a99d; color: #fff; font-size: .64rem; font-weight: 800; display: flex; align-items: center; justify-content: center; }
.sc-jlbl { font-family: 'Inter', sans-serif; font-size: 13.4px; font-weight: 700; color: #0b2545; margin-bottom: 4px; }
.sc-jdsc { font-size: 11.5px; color: #566983; max-width: 82px; line-height: 1.5; }

/* ─── TESTIMONIALS ─── */
.sc-testi { background: #fff; }
.sc-tgrid { display: grid; grid-template-columns: repeat(3,1fr); gap: 1.5rem; }
.sc-tcard { background: #f7fafd; border-radius: 12px; border: 1px solid #dce8f5; padding: 2rem; transition: all .3s; }
.sc-tcard:hover { box-shadow: 0 8px 36px rgba(11,37,69,.11); transform: translateY(-4px); }
.sc-tq { font-size: 48px; line-height: 1; color: #e8f2fc; font-family: Georgia, serif; margin-bottom: 6.4px; }
.sc-tstars { color: #f59e0b; font-size: 13.6px; letter-spacing: 2px; margin-bottom: 11.2px; }
.sc-ttext { font-size: 14.1px; color: #566983; line-height: 1.75; font-style: italic; margin-bottom: 20.8px; }
.sc-tauthor { display: flex; align-items: center; gap: 10px; }
.sc-tavatar { width: 42px; height: 42px; border-radius: 50%; object-fit: cover; border: 2px solid #dce8f5; }
.sc-tname { font-family: 'Inter', sans-serif; font-size: 14px; font-weight: 700; color: #0b2545; }
.sc-trole { font-size: 11.5px; color: #566983; }

/* ─── APPOINTMENT CTA ─── */
.sc-appt-cta { background: linear-gradient(120deg, #0d5eaf 0%, #0b2545 100%); padding: 5rem 2rem; text-align: center; position: relative; overflow: hidden; }
.sc-appt-cta::before { content: ''; position: absolute; width: 500px; height: 500px; border-radius: 50%; background: rgba(255,255,255,.04); top: -220px; left: -120px; }
.sc-appt-cta::after { content: ''; position: absolute; width: 420px; height: 420px; border-radius: 50%; background: rgba(0,169,157,.1); bottom: -210px; right: -60px; }
.sc-appt-cta h2 { font-size: clamp(28.8px, 3.5vw, 44.8px); color: #fff; margin-bottom: 14.4px; position: relative; z-index: 1; }
.sc-appt-cta p { color: rgba(255,255,255,.7); font-size: 16.8px; max-width: 470px; margin: 0 auto 40px; line-height: 1.7; position: relative; z-index: 1; }
.sc-appt-form { display: flex; gap: .75rem; justify-content: center; flex-wrap: wrap; position: relative; z-index: 1; }
.sc-appt-form select, .sc-appt-form input[type="date"], .sc-appt-form input[type="text"] { padding: 12.5px 18.4px; border-radius: 9px; border: none; background: rgba(255,255,255,.14); color: #fff; font-family: 'Inter', sans-serif; font-size: 14px; backdrop-filter: blur(6px); outline: none; min-width: 175px; }
.sc-appt-form select option { color: #0b2545; background: #fff; }
.sc-appt-form ::placeholder { color: rgba(255,255,255,.6); }
.sc-appt-form button { padding: 12.5px 32px; background: #00a99d; color: #fff; border: none; border-radius: 9px; font-weight: 700; font-size: 15.2px; cursor: pointer; transition: all .2s; }
.sc-appt-form button:hover { background: #009088; transform: translateY(-2px); }

/* ─── FOOTER ─── */
.sc-footer { background: #0b2545; color: rgba(255,255,255,.62); }
.sc-foot-top { padding: 4rem 2rem 3rem; }
.sc-fgrid { max-width: 1200px; margin: 0 auto; display: grid; grid-template-columns: 1.8fr 1fr 1fr 1fr; gap: 3rem; }
.sc-fbrand img { height: 48px; width: auto; }
.sc-fbrand p { font-size: 13.3px; line-height: 1.78; margin: 13.6px 0 19.2px; max-width: 255px; }
.sc-faccred { display: inline-flex; align-items: center; gap: 7px; background: rgba(0,169,157,.14); border: 1px solid rgba(0,169,157,.24); padding: 5px 12px; border-radius: 6px; font-size: 11.5px; color: #7ed8d3; font-weight: 600; }
.sc-faccred svg { width: 13px; height: 13px; fill: #00a99d; }
.sc-fcol h4 { font-family: 'Inter', sans-serif; font-size: 12.5px; font-weight: 700; color: #fff; margin-bottom: 1rem; letter-spacing: .06em; text-transform: uppercase; }
.sc-flinks { list-style: none; display: flex; flex-direction: column; gap: .5rem; }
.sc-flinks a { color: rgba(255,255,255,.52); font-size: 13.3px; transition: color .2s; }
.sc-flinks a:hover { color: #fff; }
.sc-fcontact { display: flex; flex-direction: column; gap: .7rem; }
.sc-fci { display: flex; align-items: flex-start; gap: 9px; font-size: 13.1px; }
.sc-fci svg { width: 15px; height: 15px; fill: #00a99d; flex-shrink: 0; margin-top: 3px; }
.sc-foot-bottom { border-top: 1px solid rgba(255,255,255,.07); padding: 22.4px 2rem; max-width: 1200px; margin: 0 auto; display: flex; justify-content: space-between; align-items: center; font-size: 12.5px; flex-wrap: wrap; gap: .75rem; }
.sc-fbot-links { display: flex; gap: 1.4rem; }
.sc-fbot-links a { color: rgba(255,255,255,.38); transition: color .2s; }
.sc-fbot-links a:hover { color: #fff; }

/* ─── MODAL ─── */
.sc-modal-overlay { position: fixed; inset: 0; z-index: 2000; background: rgba(11,37,69,0.72); backdrop-filter: blur(6px); display: flex; align-items: center; justify-content: center; padding: 1rem; opacity: 0; pointer-events: none; transition: opacity .3s ease; }
.sc-modal-overlay.open { opacity: 1; pointer-events: all; }
.sc-modal-box { background: #fff; border-radius: 20px; width: 100%; max-width: 580px; box-shadow: 0 32px 80px rgba(11,37,69,.28); overflow: hidden; transform: translateY(24px) scale(0.97); transition: transform .35s cubic-bezier(.34,1.4,.64,1), opacity .3s ease; opacity: 0; }
.sc-modal-overlay.open .sc-modal-box { transform: translateY(0) scale(1); opacity: 1; }
.sc-modal-head { background: linear-gradient(120deg, #0d5eaf 0%, #0b2545 100%); padding: 1.6rem 2rem; position: relative; }
.sc-modal-head h3 { color: #fff; font-family: 'Playfair Display', serif; font-size: 22.4px; font-weight: 800; margin-bottom: 4.8px; }
.sc-modal-head p { color: rgba(255,255,255,.68); font-size: 13.4px; }
.sc-modal-close { position: absolute; top: 19px; right: 22px; background: rgba(255,255,255,.12); border: none; color: #fff; width: 32px; height: 32px; border-radius: 50%; cursor: pointer; font-size: 16px; display: flex; align-items: center; justify-content: center; transition: background .2s; }
.sc-modal-close:hover { background: rgba(255,255,255,.25); }
.sc-modal-body { padding: 28.8px 32px; }
.sc-form-row { display: grid; grid-template-columns: 1fr 1fr; gap: 1rem; margin-bottom: 1rem; }
.sc-form-row.full { grid-template-columns: 1fr; }
.sc-form-group { display: flex; flex-direction: column; gap: 6.4px; position: relative; }
.sc-form-group label { font-size: 12.5px; font-weight: 700; color: #0b2545; letter-spacing: .04em; text-transform: uppercase; }
.sc-form-group input, .sc-form-group select, .sc-form-group textarea { padding: 11.2px 15.2px; border-radius: 9px; border: 1.5px solid #dce8f5; font-family: 'Inter', sans-serif; font-size: 14.4px; color: #1a2b45; background: #fff; outline: none; transition: border-color .2s, box-shadow .2s; width: 100%; }
.sc-form-group input:focus, .sc-form-group select:focus, .sc-form-group textarea:focus { border-color: #0d5eaf; box-shadow: 0 0 0 3px rgba(13,94,175,.12); }
.sc-form-group input.sc-err, .sc-form-group select.sc-err { border-color: #dc2626; }
.sc-form-group textarea { resize: vertical; min-height: 72px; }
.sc-modal-submit { width: 100%; padding: 14.4px; border: none; border-radius: 10px; background: #0d5eaf; color: #fff; font-family: 'Playfair Display', serif; font-size: 16px; font-weight: 700; cursor: pointer; transition: all .25s; margin-top: 8px; display: flex; align-items: center; justify-content: center; gap: 8px; }
.sc-modal-submit:hover { background: #0b2545; transform: translateY(-2px); box-shadow: 0 8px 24px rgba(13,94,175,.35); }
.sc-modal-submit:disabled { background: #566983; cursor: not-allowed; transform: none; box-shadow: none; }
.sc-modal-divider { border: none; border-top: 1px solid #dce8f5; margin: 1.2rem 0; }
.sc-modal-success, .sc-modal-error { display: none; text-align: center; padding: 2.5rem 2rem; }
.sc-modal-success.show, .sc-modal-error.show { display: block; }
.sc-modal-form-area.hidden { display: none; }
.sc-success-icon { width: 64px; height: 64px; border-radius: 50%; background: #e4f7f6; margin: 0 auto 1rem; display: flex; align-items: center; justify-content: center; }
.sc-success-icon svg { width: 30px; height: 30px; fill: #00a99d; }
.sc-error-icon { width: 64px; height: 64px; border-radius: 50%; background: #fef2f2; margin: 0 auto 1rem; display: flex; align-items: center; justify-content: center; }
.sc-error-icon svg { width: 30px; height: 30px; fill: #dc2626; }
.sc-modal-success h4, .sc-modal-error h4 { font-size: 19.2px; color: #0b2545; margin-bottom: 8px; }
.sc-modal-success p, .sc-modal-error p { font-size: 14px; color: #566983; line-height: 1.7; }
.sc-doc-loading-badge { position: absolute; right: 10px; top: 32px; font-size: .7rem; color: #0d5eaf; display: flex; align-items: center; gap: 4px; }
.sc-sn-note { font-size: .72rem; color: #566983; text-align: center; margin-top: .85rem; display: flex; align-items: center; justify-content: center; gap: 5px; }
.sc-sn-note svg { width: 13px; height: 13px; fill: #00a99d; }
.sc-spinner { width: 18px; height: 18px; border: 2.5px solid rgba(255,255,255,.3); border-top-color: #fff; border-radius: 50%; animation: sc-spin .7s linear infinite; display: inline-block; }
.sc-spinner-sm { width: 12px; height: 12px; border: 2px solid rgba(13,94,175,.25); border-top-color: #0d5eaf; border-radius: 50%; animation: sc-spin .7s linear infinite; display: inline-block; }
@keyframes sc-spin { to { transform: rotate(360deg) } }

/* ─── RESPONSIVE ─── */
@media(max-width:1040px) {
  .sc-hero-float { display: none; }
  .sc-why-grid { grid-template-columns: 1fr; }
  .sc-why-left { display: none; }
}
@media(max-width:900px) {
  .sc-qgrid, .sc-doc-grid { grid-template-columns: repeat(2,1fr); }
  .sc-dgrid { grid-template-columns: repeat(2,1fr); }
  .sc-trust-inner { grid-template-columns: repeat(2,1fr); }
  .sc-jsteps { grid-template-columns: repeat(3,1fr); gap: 1.5rem; }
  .sc-jsteps::before { display: none; }
  .sc-tgrid { grid-template-columns: repeat(2,1fr); }
  .sc-fgrid { grid-template-columns: 1fr 1fr; }
  .sc-nb-outline { display: none; }
}
@media(max-width:620px) {
  .sc-strip { flex-direction: column; gap: .5rem; text-align: center; }
  .sc-qgrid, .sc-doc-grid, .sc-dgrid, .sc-trust-inner, .sc-tgrid { grid-template-columns: 1fr; }
  .sc-jsteps { grid-template-columns: repeat(2,1fr); }
  .sc-fgrid { grid-template-columns: 1fr; }
  .sc-nav-menu { display: none; }
  .sc-form-row { grid-template-columns: 1fr; }
}

sp_widget.script:
(function() {
  data.snTable = 'x_1954503_smartc_0_smartcare_appointment';

  var stats = {
    specialists:   '50+',
    departments:   '15+',
    patients:      '0',
    emergency:     '24/7',
    doctorsOnDuty: 'Doctors Available',
    bedsReady:     'Beds Available',
    waitTime:      '~12 minutes'
  };

  // 1. doctors in SmartCare Hospital Doctors group
  //    build a map: dept -> [{name, sys_id}]
  var doctorsByDept = {};
  try {
    var grDr = new GlideRecord('sys_user_grmember');
    grDr.addEncodedQuery('group.name=SmartCare Hospital Doctors^user.active=true');
    grDr.setLimit(500);
    grDr.query();
    var drCount = 0;
    while (grDr.next()) {
      drCount++;
      // getDisplayValue for dot-walked fields, getValue('user') for the reference sys_id
      var dept  = grDr.getDisplayValue('user.u_medical_department') || 'Unknown';
      var name  = grDr.getDisplayValue('user.name') || 'Unknown Doctor';
      // getValue on a reference field returns the referenced record's sys_id directly
      var sysId = grDr.getValue('user') || name; // fallback to name so value is never empty
      if (!doctorsByDept[dept]) doctorsByDept[dept] = [];
      doctorsByDept[dept].push({ name: name, sys_id: sysId });
    }
    stats.doctorsOnDuty = drCount + ' Specialist' + (drCount !== 1 ? 's' : '') + ' Available';
    stats.specialists   = (drCount >= 500 ? '500+' : drCount + '+');
  } catch(e) { /* keep defaults */ }

  data.doctorsByDept = doctorsByDept;
  // debug: list of department keys found, so you can compare vs HTML option values
  data.doctorDepts = Object.keys(doctorsByDept);

  // 2. available beds
  try {
    var grBed = new GlideRecord('x_1954503_smartc_0_hospital_bed');
    grBed.addEncodedQuery('available=true');
    grBed.setLimit(1000);
    grBed.query();
    var bedCount = 0;
    while (grBed.next()) bedCount++;
    if (bedCount === 0) {
      // try without filter
      var grBed2 = new GlideRecord('x_1954503_smartc_0_hospital_bed');
      grBed2.setLimit(1000);
      grBed2.query();
      while (grBed2.next()) bedCount++;
    }
    stats.bedsReady = bedCount + ' Bed' + (bedCount !== 1 ? 's' : '') + ' Ready';
  } catch(e) { /* keep defaults */ }

  // 3. total patients
  try {
    var grPat = new GlideRecord('x_1954503_smartc_0_patient');
    grPat.setLimit(10000);
    grPat.query();
    var patCount = 0;
    while (grPat.next()) patCount++;
    stats.patients = patCount > 0 ? patCount.toLocaleString() + '+' : '0';
  } catch(e) { /* keep defaults */ }

  // 4. medical departments (from sys_choice)
  try {
    var grDept = new GlideRecord('sys_choice');
    grDept.addEncodedQuery('name=sys_user^element=u_medical_department^inactive=false');
    grDept.setLimit(50);
    grDept.query();
    var deptCount = 0;
    while (grDept.next()) deptCount++;
    stats.departments = deptCount > 0 ? deptCount + '+' : '15+';
  } catch(e) { /* keep defaults */ }

  // 5. emergency cases
  try {
    var grEmg = new GlideRecord('x_1954503_smartc_0_emergency_cases');
    grEmg.setLimit(10000);
    grEmg.query();
    var emgCount = 0;
    while (grEmg.next()) emgCount++;
    stats.emergency = emgCount > 0 ? emgCount.toLocaleString() + '+' : '24/7';
  } catch(e) { /* keep defaults */ }

  data.stats = stats;

  // ── handle appointment submission from client ──────────────────────
  if (input && input.action === 'submitAppointment') {
    var f = input.form;
    var result = { ok: false, sys_id: '', error: '' };
    try {
      var notesText = 'Department: ' + f.dept + ' | Phone: ' + f.phone;
      if (f.email) notesText += ' | Email: ' + f.email;
      if (f.notes) notesText += ' | Reason: ' + f.notes;

      var grAppt = new GlideRecord('x_1954503_smartc_0_smartcare_appointment');
      grAppt.initialize();
      grAppt.setValue('patient',          f.name);
      grAppt.setValue('appointment_date', f.date);
      grAppt.setValue('appointment_time', f.time);
      grAppt.setValue('status',           'scheduled');
      grAppt.setValue('notes',            notesText);
      grAppt.setValue('doctor',           f.doctor);
      if (f.gender) grAppt.setValue('gender', f.gender);
      if (f.age)    grAppt.setValue('age',    f.age);
      var newSysId = grAppt.insert();
      if (newSysId) {
        result.ok     = true;
        result.sys_id = newSysId;
      } else {
        result.error = 'Insert returned no sys_id';
      }
    } catch(e) {
      result.error = e.message || String(e);
    }
    data.submitResult = result;
  }

})();
